patch:
--- a/decoder.sv
+++ b/decoder.sv
@@ -1,15 +1,15 @@
 module decoder_32bit(
   input wire [4:0] address,
-  output reg [31:0] decoded_out
+  output reg [31:0] decoded_out,
+  input wire valid_en
 );
   always @(*) begin
-    decoded_out = 32'b0;
-    decoded_out[address] = 1'b1;
+    if (valid_en) begin
+      decoded_out = 32'b0;
+      decoded_out[address] = 1'b1;
+    end else
+      decoded_out = 32'b0;
   end
 endmodule

 module top_module;
   wire [4:0] addr;
-  wire [31:0] out;
-  decoder_32bit dec (.address(addr), .decoded_out(out), .valid_en(1'b1));
+  wire [31:0] out;
+  decoder_32bit dec (.address(addr), .decoded_out(out), .valid_en(1'b1));
 endmodule

before_code:
module decoder_32bit(
  input wire [4:0] address,
  output reg [31:0] decoded_out
);
  always @(*) begin
    decoded_out = 32'b0;
    decoded_out[address] = 1'b1;
  end
endmodule

module top_module;
  wire [4:0] addr;
  wire [31:0] out;
  decoder_32bit dec (.address(addr), .decoded_out(out), .valid_en(1'b1));
endmodule

after_code:
module decoder_32bit(
  input wire [4:0] address,
  output reg [31:0] decoded_out,
  input wire valid_en
);
  always @(*) begin
    if (valid_en) begin
      decoded_out = 32'b0;
      decoded_out[address] = 1'b1;
    end else
      decoded_out = 32'b0;
  end
endmodule

module top_module;
  wire [4:0] addr;
  wire [31:0] out;
  decoder_32bit dec (.address(addr), .decoded_out(out), .valid_en(1'b1));
endmodule
